fn solve(n: i64) -> String {
    // Function to convert a number to hexadecimal (base 16)
    fn to_hex(num: i64) -> String {
        let hex_digits = "0123456789ABCDEF";
        let mut result = String::new();
        let mut num = num;
        while num > 0 {
            let remainder = num % 16;
            result = format!("{}{}", hex_digits[remainder as usize], result);
            num = num / 16;
        }
        if result.is_empty() {
            "0".to_string()
        } else {
            result
        }
    }

    // Function to convert a number to base 36
    fn to_base36(num: i64) -> String {
        let base36_digits = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
        let mut result = String::new();
        let mut num = num;
        while num > 0 {
            let remainder = num % 36;
            result = format!("{}{}", base36_digits[remainder as usize], result);
            num = num / 36;
        }
        if result.is_empty() {
            "0".to_string()
        } else {
            result
        }
    }

    let n2 = n * n;
    let n3 = n * n * n;

    let hex_part = to_hex(n2);
    let base36_part = to_base36(n3);

    format!("{}{}", hex_part, base36_part)
}
